public static readonly LlamaLibrary.Logging.LLogger Log = new("ARR", Colors.DeepPink);

private static readonly string[] TutorialWindows =
{
    "HowToNotice",
    "HowTo",
    "PlayGuide",
    "JobHudNotice",
    "ContentsTutorial",
    "RecommendList",
    "AchievementInfo",
    "CreditScroll",
};



        bool hasTutorialWindow = TutorialWindows
            .Any(window => RaptureAtkUnitManager.GetWindowByName(window) != null);

        if (RaptureAtkUnitManager.GetWindowByName("CreditScroll") != null)
        {
            RaptureAtkUnitManager.GetWindowByName("CreditScroll").SendAction(1, 3uL, 0xFFFFFFFFuL);
        }

        if (RaptureAtkUnitManager.GetWindowByName("CreditPlayer") != null)
        {
            RaptureAtkUnitManager.GetWindowByName("CreditPlayer").SendAction(1, 3uL, 0xFFFFFFFFuL);
        }

        if (hasTutorialWindow)
        {
            await LlamaLibrary.Helpers.GeneralFunctions.CloseHowTos();
        }

        // Adding this as a work around as 'Terror at Fallgourd' requires an emote to turn in.
        if (QuestLogManager.HasQuest(69399) && QuestLogManager.GetQuestById(69399).Step == 255)
        {
            if (JournalResult.IsOpen)
            {
                JournalResult.Complete();
            }
        }

			  return false;


        var magitek = RoutineManager.Routines.First(i => i.Name.Contains("Magitek"));
        if (magitek != null)
        {
            Logging.WriteDiagnostic("Turning off AOE settings.");
			      Magitek.Models.Bard.BardSettings.Instance.UseAoe = false;
            Magitek.Models.Monk.MonkSettings.Instance.UseAoe = false;
            Magitek.Models.Paladin.PaladinSettings.Instance.UseAoe = false;
            Magitek.Models.Warrior.WarriorSettings.Instance.UseAoe = false;
            Magitek.Models.Summoner.SummonerSettings.Instance.Outburst = false;
            Magitek.Models.Paladin.PaladinSettings.Instance.UseShieldLobOnLostAggro = false;
        }
        else
        {
            Logging.WriteDiagnostic("Magitek not found.");
        }


        var magitek = RoutineManager.Routines.First(i => i.Name.Contains("Magitek"));
        if (magitek != null)
        {
            Logging.WriteDiagnostic("Turning on AOE settings.");
			      Magitek.Models.Bard.BardSettings.Instance.UseAoe = true;
            Magitek.Models.Monk.MonkSettings.Instance.UseAoe = true;
            Magitek.Models.Paladin.PaladinSettings.Instance.UseAoe = true;
            Magitek.Models.Warrior.WarriorSettings.Instance.UseAoe = true;
            Magitek.Models.Summoner.SummonerSettings.Instance.Outburst = true;
            Magitek.Models.Paladin.PaladinSettings.Instance.UseShieldLobOnLostAggro = true;
        }
        else
        {
            Logging.WriteDiagnostic("Magitek not found.");
        }
